from collections import defaultdict

def group_by_key(pairs):
    result = defaultdict(list)
    for key, value in pairs:
        result[key].append(value)
    return dict(result)
```

```python
def topological_sort(graph):
    in_degree = {node: 0 for node in graph}
    for node in graph:
        for dependent in graph[node]:
            if dependent not in in_degree:
                in_degree[dependent] = 0
            in_degree[dependent] += 1

    queue = [node for node in in_degree if in_degree[node] == 0]
    result = []

    while queue:
        node = queue.pop(0)
        result.append(node)
        for dependent in graph.get(node, []):
            in_degree[dependent] -= 1
            if in_degree[dependent] == 0:
                queue.append(dependent)

    if len(result) != len(in_degree):
        raise ValueError("Graph contains a cycle")

    return result
```

```python
def unique_preserve_order(items):
    seen = set()
    result = []
    for item in items:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result
```

```python
def rotate_matrix_clockwise(M):
    if not M or not M[0]:
        return []
    return [[M[i][j] for i in range(len(M) - 1, -1, -1)] for j in range(len(M[0]))]
```

```python
def decode_ranges(spec):
    result = []
    for part in spec.split(','):
        if '-' in part:
            start, end = map(int, part.split('-'))
            result.extend(range(start, end + 1))
        else:
            result.append(int(part))
    return result
```

```python
def nest_by_dots(flat):
    result = {}
    for key, value in flat.items():
        parts = key.split('.')
        current = result
        for part in parts[:-1]:
            if part not in current:
                current[part] = {}
            current = current[part]
        current[parts[-1]] = value
    return result
```

```python
def interval_gaps(intervals, start, end):
    if not intervals or start >= end:
        return [[start, end]] if start < end else []

    # Sort intervals by start time
    sorted_intervals = sorted(intervals)

    # Merge overlapping intervals
    merged = []
    if sorted_intervals:
        current_start, current_end = sorted_intervals[0]
        for next_start, next_end in sorted_intervals[1:]:
            if next_start < current_end:
                current_end = max(current_end, next_end)
            else:
                merged.append([current_start, current_end])
                current_start, current_end = next_start, next_end
        merged.append([current_start, current_end])

    # Find gaps
    gaps = []
    current_pos = start

    for interval_start, interval_end in merged:
        if interval_start > current_pos:
            gaps.append([current_pos, interval_start])
        current_pos = max(current_pos, interval_end)

    if current_pos < end:
        gaps.append([current_pos, end])

    return gaps
```
